    // === 7. FEATURE: SEND TO STATUS 40 WITH SPECIAL ACCOUNT
    // ===================================================================
    // This feature has been moved to myman_status40.js
    // The functions are available via window.initStatus40Button and window.checkPendingStatus40
    
    // ===================================================================
